<script setup lang="ts">import{ref,watch}from"vue";import{desktopApi}from"../../shared/api";import{errorMessage}from"../../shared/errors";import type{BackupDto}from"../../shared/bindings";const props=defineProps<{repository:string}>();const items=ref<BackupDto[]>([]);const message=ref("");async function refresh(){try{items.value=await desktopApi.listBackups(props.repository);}catch(e){message.value=errorMessage(e);}}async function restore(item:BackupDto){if(!confirm(`恢复 ${item.originalPath} 到备份状态？当前内容会被替换。`))return;try{message.value=(await desktopApi.restoreBackup(props.repository,item.id)).message;await refresh();}catch(e){message.value=errorMessage(e);}}watch(()=>props.repository,refresh,{immediate:true});</script>
<template><section class="panel"><header class="panel-header"><div><p class="eyebrow">安全恢复</p><h1>事务备份</h1></div><button class="button secondary" @click="refresh">刷新</button></header><p v-if="message" class="notice">{{message}}</p><div v-if="!items.length" class="empty-state"><strong>尚无备份</strong><span>每次将仓库配置应用到本机前，EnvWeave 都会自动保存原始内容。</span></div><div v-else class="backup-list"><article v-for="item in items" :key="item.id"><div><strong>{{item.originalPath}}</strong><small>{{item.id}} · {{item.existed?'原文件已保存':'记录为原本不存在'}}</small></div><button class="button secondary" @click="restore(item)">恢复</button></article></div></section></template>
